export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

class CSVResultImpl implements CSVResult {
  public rows: Record<string, unknown>[];
  public headers: string[];
  public errors: CSVError[];

  public constructor(
    rows: Record<string, unknown>[],
    headers: string[],
    errors: CSVError[],
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  public filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
    return this.rows.filter(predicate);
  }

  public sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  }

  public average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  public count(): number {
    return this.rows.length;
  }

  public groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
    const grouped = new Map<unknown, Record<string, unknown>[]>();
    for (const row of this.rows) {
      const key = row[column];
      const bucket = grouped.get(key);
      if (bucket) {
        bucket.push(row);
      } else {
        grouped.set(key, [row]);
      }
    }
    return grouped;
  }
}

const numberPattern = /^-?\d+(?:\.\d+)?$/;

function coerceValue(value: string): unknown {
  if (value === "") {
    return null;
  }
  const lower = value.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (numberPattern.test(value)) {
    return Number(value);
  }
  return value;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator;
  const errors: CSVError[] = [];

  if (input.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const rowsRaw: string[][] = [];
  const rowNumbers: number[] = [];
  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;
  let index = 0;
  let lastWasLineSeparator = false;

  const matchLineSeparator = (start: number): number => {
    if (lineSeparator !== undefined) {
      return input.startsWith(lineSeparator, start) ? lineSeparator.length : 0;
    }
    if (input[start] === "\r" && input[start + 1] === "\n") {
      return 2;
    }
    if (input[start] === "\n" || input[start] === "\r") {
      return 1;
    }
    return 0;
  };

  while (index < input.length) {
    const separatorLength = !inQuotes ? matchLineSeparator(index) : 0;
    if (separatorLength > 0) {
      currentRow.push(currentField);
      currentField = "";
      rowsRaw.push(currentRow);
      rowNumbers.push(rowNumber);
      currentRow = [];
      rowNumber += 1;
      index += separatorLength;
      lastWasLineSeparator = true;
      continue;
    }

    lastWasLineSeparator = false;
    const char = input[index];

    if (char === quote) {
      if (inQuotes) {
        if (input[index + 1] === quote) {
          currentField += quote;
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }
      inQuotes = true;
      index += 1;
      continue;
    }

    if (char === delimiter && !inQuotes) {
      currentRow.push(currentField);
      currentField = "";
      index += 1;
      continue;
    }

    currentField += char;
    index += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unterminated quoted field" });
  } else if (
    !lastWasLineSeparator &&
    (currentRow.length > 0 ||
      currentField.length > 0 ||
      (input.length > 0 && input.endsWith(delimiter)))
  ) {
    currentRow.push(currentField);
    rowsRaw.push(currentRow);
    rowNumbers.push(rowNumber);
  }

  const headers = rowsRaw.length > 0 ? rowsRaw[0] : [];
  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < rowsRaw.length; i += 1) {
    const fields = rowsRaw[i];
    const currentRowNumber = rowNumbers[i];
    if (fields.length !== headers.length) {
      errors.push({
        row: currentRowNumber,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
      continue;
    }
    const row: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c += 1) {
      row[headers[c]] = coerceValue(fields[c]);
    }
    rows.push(row);
  }

  return new CSVResultImpl(rows, headers, errors);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(`${message} (expected ${expected}, got ${actual})`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message} (expected ${expectedJson}, got ${actualJson})`);
  }
}

const basicResult = parseCSV("name,age\nAlice,30\nBob,25");
assertDeepEqual(basicResult.headers, ["name", "age"], "Basic headers parsed");
assertEqual(basicResult.rows.length, 2, "Basic row count");
assertEqual(basicResult.rows[0].name, "Alice", "Basic row value");
assertEqual(typeof basicResult.rows[0].age, "number", "Age should be number");
assertEqual(basicResult.rows[0].age, 30, "Age value");

const quotedResult = parseCSV('name,quote\nAlice,"hello, world"');
assertEqual(quotedResult.rows[0].quote, "hello, world", "Quoted commas should parse");

const escapedResult = parseCSV('name,quote\nAlice,"She said ""Hi"""');
assertEqual(escapedResult.rows[0].quote, 'She said "Hi"', "Escaped quotes should parse");

const customDelimiterResult = parseCSV("name|age\nAlice|30", { delimiter: "|" });
assertEqual(customDelimiterResult.rows[0].age, 30, "Custom delimiter parsing");

const customQuoteResult = parseCSV("name|note\nAlice|'hello|world'", {
  delimiter: "|",
  quote: "'",
});
assertEqual(customQuoteResult.rows[0].note, "hello|world", "Custom quote parsing");

const customLineSepResult = parseCSV("a,b|1,2|3,4", { lineSeparator: "|" });
assertEqual(customLineSepResult.rows.length, 2, "Custom line separator row count");
assertEqual(customLineSepResult.rows[1].b, 4, "Custom line separator value");

const coercionResult = parseCSV(
  "int,float,bool1,bool2,null1,null2,text\n42,3.14,true,FALSE,null,,hello",
);
assertEqual(coercionResult.rows[0].int, 42, "Integer coercion");
assertEqual(coercionResult.rows[0].float, 3.14, "Float coercion");
assertEqual(coercionResult.rows[0].bool1, true, "Boolean coercion true");
assertEqual(coercionResult.rows[0].bool2, false, "Boolean coercion false");
assertEqual(coercionResult.rows[0].null1, null, "Null coercion literal");
assertEqual(coercionResult.rows[0].null2, null, "Null coercion empty");
assertEqual(coercionResult.rows[0].text, "hello", "Text remains string");

const malformedResult = parseCSV("a,b\n1\n2,3,4");
assertEqual(malformedResult.rows.length, 0, "Malformed rows should be skipped");
assertEqual(malformedResult.errors.length, 2, "Malformed rows errors collected");
assertEqual(malformedResult.errors[0].row, 2, "Malformed row number for short row");
assertEqual(malformedResult.errors[1].row, 3, "Malformed row number for long row");

const filterResult = parseCSV("name,age\nAlice,30\nBob,20");
const filteredRows = filterResult.filter((row) => (row.age as number) > 25);
assertEqual(filteredRows.length, 1, "Filter should return matching rows");
assertEqual(filteredRows[0].name, "Alice", "Filter result content");

const aggregationResult = parseCSV(
  "name,dept,salary\nA,Eng,100\nB,Eng,200\nC,HR,150",
);
assertEqual(aggregationResult.sum("salary"), 450, "Sum aggregation");
assertEqual(aggregationResult.average("salary"), 150, "Average aggregation");
assertEqual(aggregationResult.count(), 3, "Count aggregation");
const grouped = aggregationResult.groupBy("dept");
assertEqual(grouped.get("Eng")?.length, 2, "GroupBy Eng count");
assertEqual(grouped.get("HR")?.length, 1, "GroupBy HR count");

const emptyResult = parseCSV("");
assertEqual(emptyResult.rows.length, 0, "Empty input row count");
assertEqual(emptyResult.headers.length, 0, "Empty input headers");
assertEqual(emptyResult.errors.length, 0, "Empty input errors");

const singleColumnResult = parseCSV("name\nAlice");
assertDeepEqual(singleColumnResult.headers, ["name"], "Single column headers");
assertEqual(singleColumnResult.rows.length, 1, "Single row count");
assertEqual(singleColumnResult.rows[0].name, "Alice", "Single row value");

const largeField = "x".repeat(10000);
const largeFieldResult = parseCSV(`data\n${largeField}`);
assertEqual(
  (largeFieldResult.rows[0].data as string).length,
  10000,
  "Large field should parse",
);

console.log("All CSV parser tests passed.");

